# Qdrant native sparse vectors (v1.7+) — no separate BM25 index needed
# Requires SPLADE or similar sparse encoder model
from qdrant_client.models import (
    VectorParams, SparseVectorParams, Distance,
    PointStruct, SparseVector,
    NamedVector, NamedSparseVector,
)

client.create_collection(
    'hybrid_native',
    vectors_config={
        'dense':  VectorParams(size=1024, distance=Distance.COSINE),
    },
    sparse_vectors_config={
        'sparse': SparseVectorParams(),
    },
)

# Upsert with both dense and sparse vectors
import numpy as np
client.upsert('hybrid_native', points=[
    PointStruct(
        id='doc-0',
        vector={
            'dense':  np.random.rand(1024).tolist(),
            'sparse': SparseVector(
                indices=[42, 101, 512, 8001],  # non-zero token IDs
                values=[0.82, 0.54, 0.31, 0.21],  # SPLADE weights
            ),
        },
        payload={'text': 'Annual budget 2024 shows 15% R&D increase'},
    )
])

# Hybrid query: Qdrant fuses dense and sparse internally with RRF
from qdrant_client.models import Prefetch, FusionQuery, Fusion

results = client.query_points(
    'hybrid_native',
    prefetch=[
        Prefetch(query=np.random.rand(1024).tolist(), using='dense',  limit=20),
        Prefetch(query=SparseVector(indices=[42, 101], values=[0.9, 0.7]),
                 using='sparse', limit=20),
    ],
    query=FusionQuery(fusion=Fusion.RRF),
    limit=5,
    with_payload=True,
)
